SELECT EXISTS(
    SELECT 1
    FROM user_accounts
    WHERE username = #{username}
)

SELECT
FROM user_accounts
role_code = #{roleCode}
AND enabled = #{enabled}
ORDER BY CASE role_code WHEN 'ADMIN' THEN 1 WHEN 'WORKER' THEN 2 WHEN 'STUDENT' THEN 3 ELSE 9 END, id ASC

